package session

import (
    "time"

    "github.com/hashicorp/boundary/internal/common"
    "github.com/hashicorp/boundary/internal/servers/controller"
)

// SessionConnectionCleanupJob is an alias to the controller implementation.
type SessionConnectionCleanupJob = controller.SessionConnectionCleanupJob

// NewSessionConnectionCleanupJob creates a new job by delegating to the controller.
func NewSessionConnectionCleanupJob(connectionRepoFn common.ConnectionRepoFactory, gracePeriod time.Duration) (*SessionConnectionCleanupJob, error) {
    return controller.NewSessionConnectionCleanupJob(connectionRepoFn, gracePeriod)
}
